-- Correct: status update and billing debit in one transaction
BEGIN;
UPDATE runs SET status = 'completed', finished_at = now() WHERE id = $1;
UPDATE billing_ledger SET credits_used = credits_used + $2 WHERE user_id = $3;
INSERT INTO tool_events (run_id, tool_name, status) VALUES ($1, 'llm_call', 'success');
COMMIT;

-- If any statement fails, ROLLBACK prevents partial state

-- Core agent schema (PostgreSQL)
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

CREATE TABLE users (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email       TEXT NOT NULL UNIQUE,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE api_keys (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id     UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  key_hash    TEXT NOT NULL UNIQUE,   -- store bcrypt hash, never plaintext
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
  revoked_at  TIMESTAMPTZ
);

CREATE TABLE sessions (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id     UUID NOT NULL REFERENCES users(id),
  metadata    JSONB NOT NULL DEFAULT '{}',
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
  last_active TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE runs (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  session_id   UUID NOT NULL REFERENCES sessions(id),
  status       TEXT NOT NULL CHECK (status IN ('queued','running','completed','failed','cancelled')),
  model        TEXT NOT NULL,
  input_tokens  INT  NOT NULL DEFAULT 0,
  output_tokens INT  NOT NULL DEFAULT 0,
  error_msg    TEXT,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT now(),
  finished_at  TIMESTAMPTZ
);

CREATE TABLE tool_events (
  id          BIGSERIAL PRIMARY KEY,
  run_id      UUID NOT NULL REFERENCES runs(id),
  tool_name   TEXT NOT NULL,
  args_json   JSONB,
  result_ref  TEXT,                  -- S3 key for large results
  status      TEXT NOT NULL CHECK (status IN ('called','success','error')),
  duration_ms INT,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Indexes
CREATE INDEX ON sessions (user_id);
CREATE INDEX ON runs (session_id, created_at DESC);
CREATE INDEX ON runs (status) WHERE status IN ('queued','running');
CREATE INDEX ON tool_events (run_id, created_at);
CREATE INDEX ON tool_events USING GIN (args_json);  -- JSONB search

-- Range-partitioned tool_events
CREATE TABLE tool_events (
  id         BIGSERIAL,
  run_id     UUID NOT NULL,
  tool_name  TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
) PARTITION BY RANGE (created_at);

CREATE TABLE tool_events_2025_01
  PARTITION OF tool_events
  FOR VALUES FROM ('2025-01-01') TO ('2025-02-01');

CREATE TABLE tool_events_2025_02
  PARTITION OF tool_events
  FOR VALUES FROM ('2025-02-01') TO ('2025-03-01');

-- Drop old partition (fast, no DELETE overhead)
-- DROP TABLE tool_events_2024_06;

-- Create a least-privilege application role
CREATE ROLE agent_api LOGIN PASSWORD 'use_a_secret_manager_not_this';

-- Grant only what the API needs
GRANT SELECT, INSERT, UPDATE ON runs, sessions, tool_events TO agent_api;
GRANT SELECT ON users TO agent_api;

-- Revoke all other default permissions
REVOKE ALL ON ALL TABLES IN SCHEMA public FROM PUBLIC;

-- Never run the API as the superuser (postgres role)
